CODE_EXAMPLE:
public class PricingService {
  public decimal FinalPrice(decimal amount) {
    return ApplyVat(amount);
  }

  private decimal ApplyVat(decimal amount) {
    return amount * 1.2m;
  }

  public decimal FinalPriceInlined(decimal amount) {
    return amount * 1.2m;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void FinalPriceAndInlinedVersion_ReturnSameValue() {
  var service = new PricingService();
  Assert.AreEqual(service.FinalPrice(100m), service.FinalPriceInlined(100m));
}

[TestMethod]
public void FinalPriceInlined_AppliesVat() {
  var service = new PricingService();
  Assert.AreEqual(120m, service.FinalPriceInlined(100m));
}
